(function () {
  'use strict';
  var reduceMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  var header = document.querySelector('.site-header');
  function onScroll() {
    header.classList.toggle('is-solid', window.scrollY > 40);
  }
  window.addEventListener('scroll', onScroll, { passive: true });
  onScroll();
  var toggle = document.querySelector('.nav-toggle');
  var nav = document.getElementById('site-nav');
  if (toggle && nav) {
    toggle.addEventListener('click', function () {
      var open = nav.classList.toggle('is-open');
      toggle.setAttribute('aria-expanded', open ? 'true' : 'false');
      toggle.setAttribute('aria-label', open ? 'Close menu' : 'Open menu');
      document.body.style.overflow = open ? 'hidden' : '';
    });
    nav.addEventListener('click', function (e) {
      if (e.target.tagName === 'A' && nav.classList.contains('is-open')) {
        nav.classList.remove('is-open');
        toggle.setAttribute('aria-expanded', 'false');
        document.body.style.overflow = '';
      }
    });
  }
  var revealEls = [].slice.call(document.querySelectorAll('.reveal'));
  var counters = [].slice.call(document.querySelectorAll('[data-count]'));
  function fmt(n) {
    try { return n.toLocaleString('en-AU'); } catch (e) { return String(n); }
  }
  function revealNow(el) { el.classList.add('is-in'); }
  function runCounter(el) {
    if (el.getAttribute('data-counted')) return;
    el.setAttribute('data-counted', '1');
    var target = parseInt(el.getAttribute('data-count'), 10) || 0;
    if (reduceMotion) { el.textContent = fmt(target); return; }
    var start = null, dur = 1800;
    function step(ts) {
      if (!start) start = ts;
      var p = Math.min((ts - start) / dur, 1);
      el.textContent = fmt(Math.floor((1 - Math.pow(1 - p, 3)) * target));
      if (p < 1) { requestAnimationFrame(step); } else { el.textContent = fmt(target); }
    }
    requestAnimationFrame(step);
  }
  function inView(el, margin) {
    var r = el.getBoundingClientRect();
    var vh = window.innerHeight || document.documentElement.clientHeight;
    return r.top < vh - (margin || 0) && r.bottom > 0;
  }
  if (reduceMotion) {
    revealEls.forEach(revealNow);
    counters.forEach(function (el) { el.textContent = fmt(parseInt(el.getAttribute('data-count'), 10) || 0); });
  } else {
    if ('IntersectionObserver' in window) {
      var revealIO = new IntersectionObserver(function (entries) {
        entries.forEach(function (e) { if (e.isIntersecting) { revealNow(e.target); revealIO.unobserve(e.target); } });
      }, { threshold: 0.12, rootMargin: '0px 0px -40px 0px' });
      revealEls.forEach(function (el) { revealIO.observe(el); });
      var countIO = new IntersectionObserver(function (entries) {
        entries.forEach(function (e) { if (e.isIntersecting) { runCounter(e.target); countIO.unobserve(e.target); } });
      }, { threshold: 0.5 });
      counters.forEach(function (el) { countIO.observe(el); });
    }
    var sweep = function () {
      revealEls.forEach(function (el) { if (!el.classList.contains('is-in') && inView(el, 40)) revealNow(el); });
      counters.forEach(function (el) { if (!el.getAttribute('data-counted') && inView(el, 0)) runCounter(el); });
    };
    window.addEventListener('load', sweep, { passive: true });
    window.addEventListener('scroll', sweep, { passive: true });
    window.addEventListener('resize', sweep, { passive: true });
    setTimeout(sweep, 1400);
    sweep();
  }
  [].forEach.call(document.querySelectorAll('.ba'), function (ba) {
    var range = ba.querySelector('input[type="range"]');
    if (!range) return;
    function setPos(v) { ba.style.setProperty('--ba-pos', v + '%'); }
    range.addEventListener('input', function () { setPos(range.value); });
    setPos(range.value);
  });
  var playBtn = document.getElementById('play-showreel');
  if (playBtn) {
    playBtn.addEventListener('click', function () {
      var frame = document.getElementById('showreel-frame');
      var video = document.createElement('video');
      video.src = 'assets/video/showreel.mp4';
      video.controls = true;
      video.autoplay = true;
      video.playsInline = true;
      video.setAttribute('aria-label', 'Sixth Vision showreel');
      frame.appendChild(video);
      playBtn.remove();
      video.play().catch(function () {  });
    });
  }
  var parallaxImg = document.querySelector('[data-parallax]');
  if (parallaxImg && !reduceMotion && 'IntersectionObserver' in window) {
    var band = parallaxImg.closest('.drone-band');
    var active = false, ticking = false;
    function parallax() {
      ticking = false;
      var rect = band.getBoundingClientRect();
      var vh = window.innerHeight;
      var progress = (rect.top + rect.height / 2 - vh / 2) / (vh / 2 + rect.height / 2);
      var shift = Math.max(-1, Math.min(1, progress)) * -5; 
      parallaxImg.style.transform = 'translateY(' + shift.toFixed(2) + '%)';
    }
    function requestParallax() {
      if (!ticking && active) { ticking = true; requestAnimationFrame(parallax); }
    }
    new IntersectionObserver(function (entries) {
      active = entries[0].isIntersecting;
      if (active) requestParallax();
    }).observe(band);
    window.addEventListener('scroll', requestParallax, { passive: true });
  }
  var lightbox = document.getElementById('lightbox');
  var triggers = [].slice.call(document.querySelectorAll('.work-trigger'));
  if (lightbox && triggers.length) {
    var lbImg = lightbox.querySelector('.lightbox-img');
    var lbCaption = lightbox.querySelector('.lightbox-caption');
    var lbCount = lightbox.querySelector('.lightbox-count');
    var btnClose = lightbox.querySelector('.lightbox-close');
    var btnPrev = lightbox.querySelector('.lightbox-prev');
    var btnNext = lightbox.querySelector('.lightbox-next');
    var current = 0, lastFocus = null;
    function show(i) {
      current = (i + triggers.length) % triggers.length;
      var t = triggers[current];
      var full = t.getAttribute('data-lightbox-src');
      var cap = t.getAttribute('data-lightbox-caption') || '';
      lbImg.src = full;
      lbImg.alt = cap;
      lbCaption.textContent = cap;
      lbCount.textContent = (current + 1) + ' / ' + triggers.length;
    }
    function open(i) {
      lastFocus = document.activeElement;
      show(i);
      lightbox.classList.add('is-open');
      lightbox.setAttribute('aria-hidden', 'false');
      document.body.style.overflow = 'hidden';
      btnClose.focus();
    }
    function close() {
      lightbox.classList.remove('is-open');
      lightbox.setAttribute('aria-hidden', 'true');
      document.body.style.overflow = '';
      if (lastFocus && lastFocus.focus) lastFocus.focus();
    }
    triggers.forEach(function (t, i) {
      t.addEventListener('click', function () { open(i); });
    });
    btnClose.addEventListener('click', close);
    btnPrev.addEventListener('click', function () { show(current - 1); });
    btnNext.addEventListener('click', function () { show(current + 1); });
    lightbox.addEventListener('click', function (e) {
      if (e.target === lightbox) close();
    });
    document.addEventListener('keydown', function (e) {
      if (!lightbox.classList.contains('is-open')) return;
      if (e.key === 'Escape') close();
      else if (e.key === 'ArrowLeft') show(current - 1);
      else if (e.key === 'ArrowRight') show(current + 1);
    });
  }
  var year = document.getElementById('year');
  if (year) { year.textContent = new Date().getFullYear(); }
})();